// Generate docs/api.md and docs/openapi.json from the single Zod/OpenAPI source
// in @stirilo/core. Run with `pnpm docs:api` (which builds core first). The
// generated files carry a banner and must not be edited by hand.
import { writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { API_ROUTES, buildOpenApiDocument } from "@stirilo/core";

const repoRoot = dirname(dirname(fileURLToPath(import.meta.url)));
const docsDir = join(repoRoot, "docs");

const BANNER =
  "<!-- Generated by scripts/generate-api-docs.mjs from @stirilo/core. " +
  "Do not edit by hand; run `pnpm docs:api`. -->";

function renderBody(route)
{
  if (!route.body)
  {
    return "";
  }
  const shape = route.body._def.shape();
  const lines = Object.entries(shape).map(([key, schema]) =>
  {
    const optional = schema.isOptional() ? "?" : "";
    return `  - \`${key}${optional}\``;
  });
  return `\n\n  Request body:\n${lines.join("\n")}`;
}

function renderMarkdown()
{
  const rows = API_ROUTES.map(
    (r) => `| ${r.method.toUpperCase()} | \`${r.path}\` | ${r.summary} |`,
  ).join("\n");

  const bodied = API_ROUTES.filter((r) => r.body);
  const bodySection = bodied
    .map(
      (r) =>
        `### ${r.method.toUpperCase()} ${r.path}${renderBody(r)}`,
    )
    .join("\n\n");

  return `${BANNER}

# Stirilo HTTP API

A local, authenticated, read-first JSON API. All routes are served by the Next.js
app under \`/api\` and bypass the session middleware (they authenticate with an
agent token instead).

## Authentication

Every request requires a bearer token matching \`STIRILO_AGENT_TOKEN\`:

\`\`\`
Authorization: Bearer <STIRILO_AGENT_TOKEN>
\`\`\`

The token is compared in constant time. Requests without a valid token receive
\`401\`. If \`STIRILO_AGENT_TOKEN\` is not configured, the API returns \`503\`.

## Error shape

All errors use a stable envelope:

\`\`\`json
{ "error": { "code": "VALIDATION_ERROR", "message": "Invalid request body.", "details": {} } }
\`\`\`

## Endpoints

| Method | Path | Description |
| --- | --- | --- |
${rows}

## Request bodies

${bodySection}

A sensitive or system path requires \`"confirm": true\`.

## Guarantees

- Secrets are never returned: no \`.env\` contents, no raw session data, no agent
  token, no environment variables.
- Mutating actions (create scan target, run scan) are recorded in the audit log.
- Responses are structured JSON suitable for AI agents.

The machine-readable schema is generated alongside this file at
[\`openapi.json\`](openapi.json).
`;
}

const markdown = renderMarkdown();
const openapi = buildOpenApiDocument();

writeFileSync(join(docsDir, "api.md"), markdown);
writeFileSync(
  join(docsDir, "openapi.json"),
  `${JSON.stringify(openapi, null, 2)}\n`,
);

console.log("Generated docs/api.md and docs/openapi.json");
